import java.util.PriorityQueue;
import java.util.Comparator;
public class Main {
    static class Node implements Comparable<Node> {
        int id, cost, and;
        Node(int id, int cost, int and) {
            this.id = id;
            this.cost = cost;
            this.and = and;
        }
        @Override
        public int compareTo(Node other) {
            return Integer.compare(this.cost, other.cost);
        }
    }
    public static void dijkstra(int n, int m, int[][] edges, int s, int t, int K) {
        int[] cost = new int[n];
        int[] and = new int[n];
        for (int i = 0; i < n; i++) {
            cost[i] = Integer.MAX_VALUE;
            and[i] = 0;
        }
        cost[s] = 0;
        and[s] = Integer.MAX_VALUE;
        PriorityQueue<Node> pq = new PriorityQueue<>();
        pq.add(new Node(s, 0, Integer.MAX_VALUE));
        while (!pq.isEmpty()) {
            Node node = pq.poll();
            for (int i = 0; i < m; i++) {
                int[] edge = edges[i];
                if (edge[0] == node.id) {
                    int new_cost = node.cost + edge[2];
                    int new_and = node.and & edge[3];
                    if (new_cost < cost[edge[1]] || (new_cost == cost[edge[1]] && new_and > and[edge[1]])) {
                        cost[edge[1]] = new_cost;
                        and[edge[1]] = new_and;
                        pq.add(new Node(edge[1], new_cost, new_and));
                    }
                }
            }
        }
        if (cost[t] == Integer.MAX_VALUE) {
            System.out.println(-1);
        } else if (and[t] >= K) {
            System.out.println(cost[t]);
        } else {
            System.out.println(-1);
        }
    }
    public static void main(String[] args) {
        // Read input
        int n = 3;
        int m = 3;
        int[][] edges = {{1, 2, 2, 3}, {2, 3, 1, 7}, {1, 3, 2, 2}};
        int s = 1;
        int t = 3;
        int K = 3;
        dijkstra(n, m, edges, s - 1, t - 1, K);
    }
}

